INSERT INTO `food_items` VALUES (1,1,'Devilled Kidneys','starter','Tender devilled kidneys served with smoked bacon, mushrooms and toasted bread delivering rich savoury depth and earthy umami flavours.',20,14,10,11,1,1,'red'),(2,1,'Short Rib Nugget','starter','Crisp short rib nugget with rich beef flavour balanced by earthy celeriac and aromatic truffle dressing.',20,16,14,10,1,1,'red'),(3,1,'F.X. Buckley Black Pudding Scotch Egg','starter','Rich black pudding scotch egg served with watercress, apple salad and smoky barbecue sauce offering savoury depth and gentle sweetness.',20,15,12,12,4,1,'red'),(4,1,'Beetroot Carpaccio','starter','Earthy beetroot carpaccio with creamy goat cheese pearls, candied walnuts, baby rocket and nutty hazelnut dressing.',20,8,2,14,5,1,'white'),(5,1,'Pan Seared Scallops','seafood','Sweet pan seared scallops served with wilted spinach, smoky Spanish chorizo, sourdough croutons and fresh chives.',20,11,2,15,1,1,'white'),(6,1,'Dry Aged Beef Tartare','starter','Finely chopped dry aged beef tartare with smoked caviar, pickled enoki mushrooms and crisp sourdough toast.',20,14,10,13,1,1,'red'),(7,1,'Chicken Liver & Foie Gras Parfait','starter','Luxuriously smooth chicken liver and foie gras parfait served with raisin and Madeira jelly alongside toasted brioche.',20,15,1,16,3,1,'white'),(8,1,'Caesar Salad','starter','Classic Caesar salad with aged Parmesan, smoked bacon and crisp leaves delivering creamy texture and savoury depth.',20,8,1,14,1,1,'white'),(9,1,'Achill Island Oysters','seafood','Fresh Achill Island oysters with bright salinity, mineral character and delicate ocean freshness.',20,4,0,18,0,1,'champagne'),(10,1,'Fillet Steak','main','Tender and lean fillet steak with delicate texture, subtle beef flavour and refined savoury depth served with crispy shoestring onions.',20,11,8,13,1,1,'red'),(11,1,'Rib Eye Steak','main','Rich marbled rib eye steak with deep savoury flavour and juicy texture served with crispy shoestring onions.',20,18,18,11,1,1,'red'),(12,1,'Striploin Steak','main','Classic striploin steak with firm texture, balanced marbling and concentrated beef character served with crispy shoestring onions.',20,17,16,12,1,1,'red'),(13,1,'Striploin on the Bone','main','Bone-in striploin steak delivering intense beef flavour, structured texture and savoury depth with crispy shoestring onions.',20,18,17,11,1,1,'red'),(14,1,'T-Bone Steak','main','Large T-bone steak combining tender fillet and richly flavoured striploin served with crispy shoestring onions.',20,18,17,11,1,1,'red'),(15,1,'Chateaubriand','main','Luxuriously tender centre cut beef fillet with refined texture, subtle savoury depth and elegant richness ideal for sharing.',20,12,9,13,1,1,'red'),(16,1,'Porterhouse Steak','main','Generous porterhouse steak combining rich marbling and tender texture with deep chargrilled beef flavours.',20,19,18,11,1,1,'red'),(17,1,'Irish Ex Dairy Cow Côte de Boeuf','main','Deeply flavoured côte de boeuf with mature beef character, rich marbling and powerful savoury complexity.',20,20,19,10,1,1,'red'),(18,1,'Ridgeway Wagyu Bone In Striploin','main','Highly marbled wagyu bone-in striploin delivering exceptional richness, buttery texture and intense umami depth.',20,20,16,12,2,1,'red'),(19,1,'6oz Beef Fillet Medallions','main','Tender beef fillet medallions served with mash, shallots, mushrooms and rich marrow jus.',20,13,10,13,1,1,'red'),(20,1,'Braised Beef Cheek','main','Slow braised beef cheek with rich gelatinous texture and deep savoury flavour served with truffle mash.',20,19,16,11,2,1,'red'),(21,1,'Cornish Sole Meuniére','seafood','Delicate Cornish sole served on the bone with buttery meunière sauce and a choice of side dish.',20,8,1,15,1,1,'white'),(22,1,'Free Range Chicken Roulade','main','Free range chicken roulade with wild garlic mousse, crispy truffle polenta, Jerusalem artichoke, roast parsnip and miso purée.',20,12,3,14,2,1,'white'),(23,1,'Coconut Custard Cake','dessert','Coconut custard cake with vanilla cream.',20,10,0,9,15,1,'dessert'),(24,1,'Espresso Pannacotta','dessert','Silky espresso pannacotta with chocolate notes.',20,12,2,8,14,1,'port'),(25,1,'Black Forest Bomb','dessert','Rich chocolate dessert with fruit compote.',20,16,4,10,18,1,'port'),(26,1,'Vanilla Creme Brulee','dessert','Classic vanilla custard with caramelised sugar.',20,11,0,14,15,1,'dessert');
