INSERT INTO `wines` VALUES (55,1,'Luma Grillo Cantina Cellaro','white','Grillo','Italy','Sicily','2024','Glass',9.00,1,'Fresh Sicilian white with citrus, pear and light floral notes, crisp acidity and a clean finish suited to seafood and salads.',20,7,1,15,1),(56,1,'Conde Valdemar Rioja Blanco','white','Viura','Spain','Rioja','2024','Glass',9.25,1,'Bright Rioja Blanco with apple, citrus and subtle almond notes, medium freshness and a clean finish for lighter starters.',20,7,1,13,1),(57,1,'Porca de Murca Branco','white','Portuguese White Blend','Portugal','Douro','2023','Glass',9.75,1,'Fresh Douro white with citrus, stone fruit and mineral notes, balanced acidity and a dry finish ideal with seafood.',20,8,1,14,1),(58,1,'Black Rock Chardonnay','white','Chardonnay','USA','California','2022','Glass',9.75,1,'Rounded Californian Chardonnay with ripe apple, peach and gentle creaminess, medium body and soft acidity for chicken or fish.',20,11,1,10,2),(59,1,'Château Bauduc Sauvignon Blanc','white','Sauvignon Blanc','France','Bordeaux','2023','Glass',10.00,1,'Fresh Bordeaux Sauvignon Blanc with citrus, green apple and herbaceous notes, lively acidity and a crisp seafood-friendly finish.',20,7,1,16,1),(60,1,'Webersburg Sauvignon Blanc','white','Sauvignon Blanc','South Africa','Stellenbosch','2024','Glass',10.25,1,'Vibrant Stellenbosch Sauvignon Blanc with lime, gooseberry and herbal notes, crisp acidity and a refreshing finish for seafood.',20,7,1,16,1),(61,1,'Picpoul de Pinet Terre de Roqueloupie','white','Picpoul','France','Languedoc','2024','Glass',10.50,1,'Zesty Picpoul with lemon, green apple and saline minerality, sharp acidity and a clean finish ideal with shellfish.',20,6,1,17,1),(62,1,'Pinot Grigio Ponte del Diavolo','white','Pinot Grigio','Italy','Veneto','2023','Glass',11.00,1,'Light Veneto Pinot Grigio with pear, citrus and floral notes, crisp acidity and a dry refreshing finish for lighter dishes.',20,6,1,13,1),(63,1,'Leefield Sauvignon Blanc Brent Marris','white','Sauvignon Blanc','New Zealand','Marlborough','2023','Glass',11.25,1,'Expressive Marlborough Sauvignon Blanc with passionfruit, lime and cut grass, high acidity and a vibrant seafood-friendly finish.',20,7,1,18,2),(64,1,'Altos de Torona Albariño Sobre Lias','white','Albariño','Spain','Rías Baixas','2023','Glass',12.50,1,'Mineral Albariño with peach, citrus and saline notes, lively acidity and a textured finish ideal with seafood and shellfish.',20,8,1,16,1),(65,1,'Sancerre Domaine Jean-Paul Ballard','white','Sauvignon Blanc','France','Loire','2024','Glass',17.50,1,'Classic Sancerre with citrus, gooseberry and flinty minerality, precise acidity and a long clean finish for seafood.',20,7,1,18,1),(66,1,'Chablis Sainte Claire Jean-Marc Brocard','white','Chardonnay','France','Chablis','2023','Glass',19.25,1,'Mineral Chablis with green apple, lemon and oyster-shell notes, crisp acidity and a precise finish suited to seafood.',20,8,1,17,1),(67,1,'La Bargemone Coteaux d’Aix-en-Provence Rosé','rose','Grenache Blend','France','Provence','2024','Glass',12.25,1,'Pale Provence rosé with red berries, citrus and floral notes, crisp acidity and a dry elegant finish for lighter dishes.',20,7,1,14,1),(68,1,'Miraval Studio Côtes de Provence Rosé','rose','Grenache Blend','France','Provence','2024','Glass',14.75,1,'Elegant Provence rosé with strawberry, peach and citrus notes, fresh acidity and a clean dry finish for seafood or salads.',20,7,1,14,1),(69,1,'Natureo Muscat Torres 0.0% Alcohol','non_alcoholic','Muscat','Spain','Penedès','NV','Glass',5.00,1,'Aromatic alcohol-free Muscat with grape, peach and floral notes, soft acidity and gentle sweetness for light dishes or aperitif.',20,5,0,8,6),(70,1,'Natureo Garnacha-Syrah Torres 0.0% Alcohol','non_alcoholic','Garnacha/Syrah','Spain','Penedès','NV','Glass',5.00,1,'Alcohol-free red blend with red berry, plum and soft spice notes, gentle tannin and a smooth finish for casual dining.',20,6,3,7,4),(71,1,'Valdespino Fino Inocente','sherry',